esqlQuery.esql:
FROM metrics-redisenterprise.otel-default
| WHERE bdb_evicted_objects IS NOT NULL
| STATS max_evictions = MAX(bdb_evicted_objects) BY bdb, cluster
// Alert when evictions are detected (peak eviction rate > 0)
// For non-caching workloads, evictions indicate memory pressure and data loss risk
// For caching workloads with eviction policies, this is expected — disable this rule
// or raise the threshold to filter out normal eviction activity
| WHERE max_evictions > 0
| SORT max_evictions DESC
